function MsIeDownload(options) {
    this.options = {
        meta: {},
        delay: 2000,
        trigger: '.js-msie-download',
        clsLoading: 'msie-loading',
    };
    Object.assign(this.options, options);
    this.setup();
}

MsIeDownload.prototype.setup = function () {
    this.bindEvents();
};

MsIeDownload.prototype.bindEvents = function () {
    document.querySelectorAll(this.options.trigger)
        .forEach(btn => btn.addEventListener('click', this.handleBtnTrigger.bind(this)));
};

MsIeDownload.prototype.handleBtnTrigger = function (e) {
    e.preventDefault();
    if (!e.target.dataset.key || parseInt(e.target.dataset.loading)) return;
    this.load(e.target, e.target.dataset.key);
};

MsIeDownload.prototype.load = async function (el, key) {
    this.beforeLoad(el);
    try {
        let request = new Request(this.options.url, {
            method: 'POST',
            cache: 'no-cache',
            body: JSON.stringify({
                key: key,
            }),
            headers: new Headers({
                'X-Requested-With': 'XMLHttpRequest',
                "Content-Type": "application/json"
            })
        });
        const response = await fetch(request);
        if (!response.ok) {
            throw new Error('Server response error!');
        }
        const data = await response.json();
        if (data.success) {
            this.options.delay = (parseInt(data.object.delay) || 2) * 1000;
            this.status(el, data.object.token);
        } else {
            this.afterLoad(el);
            this.message(data.message);
        }
    } catch (err) {
        this.afterLoad(el);
        console.log(err.message);
    }
};

MsIeDownload.prototype.download = function (token) {
    let url = this.options.url + '?act=download&token=' + token;
    window.open(url, '_blank');
};

MsIeDownload.prototype.status = async function (el, token) {
    try {
        let request = new Request(this.options.url + '?token=' + token + '&act=status', {
            method: 'GET',
            cache: 'no-cache',
            headers: new Headers({
                'X-Requested-With': 'XMLHttpRequest',
                "Content-Type": "application/json"
            })
        });
        const response = await fetch(request);
        if (!response.ok) {
            throw new Error('Server response error!');
        }
        const data = await response.json();
        if (data.success) {
            if (data.object.status === this.options.statuses.COMPLETED) {
                this.updateProgress(el, 100);
                this.afterLoad(el);
                this.download(token);
            } else if (
                data.object.status === this.options.statuses.STOPPED ||
                data.object.status === this.options.statuses.FAILED ||
                data.object.status === this.options.statuses.KILLED
            ) {
                this.afterLoad(el);
            } else {
                let rate = 0,
                    total = parseInt(data.object.total),
                    iteration = parseInt(data.object.iteration);
                if (total) {
                    rate = iteration * 100 / total;
                }
                this.updateProgress(el, rate.toFixed());
                setTimeout(() => {
                    this.status(el, token);
                }, this.options.delay);
            }
        } else {
            this.afterLoad(el);
            this.message(data.message);
        }
    } catch (err) {
        this.afterLoad(el);
        console.log(err.message);
    }
};

MsIeDownload.prototype.beforeLoad = function (el) {
    el.classList.add(this.options.clsLoading);
    el.dataset.loading = 1;
    el.dataset.text = el.innerHTML;
    el.disabled = true;
    this.updateProgress(el);
};

MsIeDownload.prototype.afterLoad = function (el) {
    el.classList.remove(this.options.clsLoading);
    el.dataset.loading = 0;
    el.innerHTML = el.dataset.text;
    el.dataset.text = el.innerHTML;
    el.disabled = false;
};

MsIeDownload.prototype.updateProgress = function (el, val) {
    val = val || 0;
    el.innerHTML = this.options.loading_text + ' ' + val + '%';
};

MsIeDownload.prototype.message = function (t, theme) {
    theme = theme || 'ms2-message-error';
    if (typeof ($.fn.jGrowl) == 'function') {
        $.jGrowl(t, {
            theme: theme,
            sticky: false
        });
    } else {
        alert(t)
        console.log(t);
    }
};